(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[237],{7828:function(e,t,n){(window.__NEXT_P=window.__NEXT_P||[]).push(["/comparisons",function(){return n(3045)}])},7747:function(e,t,n){"use strict";n.d(t,{Z:function(){return r}});var i=n(5893),a=n(9356);function r(e){let{children:t,onClick:n,style:r={}}=e;return(0,i.jsx)("div",{onClick:n,style:{background:a.Z.card,border:"1px solid ".concat(a.Z.bd),borderRadius:10,padding:"20px 18px",cursor:n?"pointer":"default",...r},children:t})}},3045:function(e,t,n){"use strict";n.r(t),n.d(t,{__N_SSG:function(){return d},default:function(){return u}});var i=n(5893),a=n(1664),r=n.n(a),s=n(326),o=n(7747),c=n(9356),l=[{slug:"headhunter-vs-linkedin",title:"Headhunter vs LinkedIn Recruiter",subtitle:"A clear comparison of retained executive search and LinkedIn Recruiter — what each approach delivers, where each falls short, and when the difference matters.",sections:[{h:"The Core Question",b:"LinkedIn Recruiter is the most widely used sourcing tool in professional recruitment, and for good reason: it provides access to the professional profiles of over 50 million UK users and enables targeted outreach at scale. At mid-market and junior-to-mid senior levels, it is often the most cost-effective and efficient way to identify and approach potential candidates. The question is not whether LinkedIn Recruiter is useful — it clearly is — but whether it is sufficient for senior executive appointments.\n\nThe fundamental limitation of LinkedIn Recruiter for executive hiring is structural. It reaches people who are reachable on LinkedIn — those who maintain active profiles, respond to InMail, and are sufficiently visible to be found through keyword search. This is not the same as reaching the best people. The most sought-after senior executives often have minimal LinkedIn presence, use their profiles passively, and have well-developed filters for distinguishing genuine executive search engagement from volume outreach.\n\nThe question for any senior hiring decision is therefore: who are we trying to reach, and is LinkedIn the right tool to reach them?"},{h:"Side-by-Side Comparison",b:"The following table compares the two approaches across the dimensions most relevant to senior hiring decisions.\n\n| Dimension | LinkedIn Recruiter | Retained Executive Search |\n|---|---|---|\n| Annual cost | \xa38,000–\xa315,000 (licence) | 25%–35% of salary (per search) |\n| Candidate universe | LinkedIn users with visible profiles | Full market including non-LinkedIn users |\n| Passive candidate reach | Limited (InMail open rates ~15–25%) | High (personal, warm approach) |\n| Assessment capability | CV review, basic screening | Competency interviews, references, reports |\n| Confidentiality | None | High |\n| Consultant seniority | Varies (often junior) | Senior partner led |\n| Candidate quality signal | Engagement with InMail | Genuine interest assessed by expert |\n| Off-limits management | None | Structured, contractual |\n| Guarantee | None | 6–12 months repeat search |\n| Aftercare | None | 3–6 months post-placement |"},{h:"Where LinkedIn Recruiter Works",b:"LinkedIn Recruiter is a strong tool for roles where the active candidate market is sufficient — senior manager, head of function, and specialist roles where there is a healthy supply of candidates who are open to approaches and have current, maintained LinkedIn profiles. For roles below director level, LinkedIn-based sourcing combined with internal assessment capability is often the most cost-effective approach.\n\nFor initial market sensing — understanding the landscape of available candidates before commissioning a formal search, or benchmarking internal candidates against the external market — LinkedIn is a useful low-cost tool. Internal talent acquisition teams with strong LinkedIn Recruiter skills and structured assessment capability can deliver good results at this level.\n\nLinkedIn is also effective when the hiring organisation's brand is strong enough to generate genuine interest without a personal introduction. Companies with household name recognition, strong employer brand, or significant market cachet often find that their InMail open rates and response quality are substantially above average."},{h:"Where LinkedIn Recruiter Falls Short",b:"For director-level appointments and above, LinkedIn Recruiter has three structural limitations that compound at higher seniority. First, coverage: the most sought-after senior executives are often the least visible on LinkedIn. They maintain minimal profiles, do not respond to InMail, and are effectively unreachable through the platform's standard tools. The candidates you can reach through LinkedIn are not necessarily the same as the candidates you want to reach.\n\nSecond, credibility: at C-suite level, a LinkedIn InMail from an unknown recruiter carries almost no weight. A senior executive who receives three or four such messages a week is not going to seriously consider an opportunity presented through this channel without a compelling reason to do so. By contrast, a personal call from a trusted executive search consultant with a genuine relationship with both the candidate and the hiring organisation carries significant weight.\n\nThird, assessment: LinkedIn Recruiter is a sourcing tool, not an assessment tool. It provides no structured evaluation of candidates beyond their self-curated profile. For senior appointments where the quality of assessment determines the quality of the hire, the absence of rigorous assessment capability is a fundamental limitation."},{h:"The Right Tool for the Right Role",b:"The pragmatic answer is that LinkedIn Recruiter and executive search are tools for different purposes, and the mistake is applying the wrong tool to a high-stakes appointment. For volume mid-market hiring, LinkedIn Recruiter — combined with strong internal assessment capability — is efficient and cost-effective. For strategic senior appointments, the structural limitations of LinkedIn-based sourcing make retained executive search the appropriate model.\n\nA useful test: could you name five people who would be excellent in this role, all of whom are currently settled in other positions and not responding to LinkedIn InMail? If yes, you need a headhunter. If the best candidate for your role is likely to be actively looking and reachable through LinkedIn, the case for executive search is weaker.\n\nThe total cost comparison also bears examination. A LinkedIn Recruiter licence costs \xa38,000–\xa315,000 annually and requires significant internal resource to operate effectively. A retained executive search for a \xa3150,000 role at 30% costs \xa345,000 but includes market mapping, candidate assessment, offer management, and a six-to-twelve-month guarantee. For the most important appointments, the economics of executive search are frequently more favourable than they appear."}],relatedLinks:[{label:"What is a Headhunter?",href:"/guides/what-is-a-headhunter/"},{label:"The Executive Search Process: Step by Step",href:"/guides/executive-search-process/"},{label:"Headhunter vs RPO",href:"/comparisons/headhunter-vs-rpo/"},{label:"Use Our Fee Estimator",href:"/estimator/"}]},{slug:"headhunter-vs-rpo",title:"Headhunter vs RPO",subtitle:"Understanding the difference between retained executive search and Recruitment Process Outsourcing — when each model delivers value, and where the boundary lies.",sections:[{h:"What is RPO?",b:'Recruitment Process Outsourcing (RPO) is a model in which an organisation outsources some or all of its internal recruitment function to a third-party provider. The RPO provider typically embeds a team within the client organisation, using the client\'s systems and processes, and takes responsibility for a defined scope of hiring — often including job advertising, applicant tracking, screening, interview coordination, and offer management.\n\nRPO is primarily designed for volume hiring: organisations with large, ongoing requirements across multiple roles and levels who want to achieve cost efficiency, consistency of process, and scalable capacity without building a proportionally sized internal team. Major RPO providers — ManpowerGroup, Allegis, Korn Ferry RPO, Cielo — offer significant technology infrastructure, global delivery capability, and the process rigour that large-scale hiring requires.\n\nThe relationship between RPO and executive search is one of scope, not competition. RPO is designed for volume and process efficiency; executive search is designed for quality and market access at senior levels. The question organisations face is not "RPO or executive search?" but "which model applies to which segment of our hiring?"'},{h:"Side-by-Side Comparison",b:"The following table compares RPO and retained executive search across the key dimensions for hiring organisations.\n\n| Dimension | RPO | Retained Executive Search |\n|---|---|---|\n| Primary purpose | Volume hiring efficiency | Senior appointment quality |\n| Typical role level | Graduate to senior manager | Director, VP, C-suite, board |\n| Fee model | Monthly retainer or per-hire | % of salary (retained) |\n| Candidate sourcing | Advertising, ATS, LinkedIn | Market mapping, direct approach |\n| Market coverage | Active candidates | Active + passive |\n| Assessment depth | Screening, structured interviews | Competency assessment, referencing, reports |\n| Confidentiality | Limited | High |\n| Scalability | High — designed for volume | Low — designed for quality |\n| Technology integration | High (ATS, HRIS) | Typically separate |\n| Guarantee | Process SLAs | Placement guarantee (6–12 months) |"},{h:"Where RPO Adds Value",b:"RPO adds genuine value for organisations with high-volume, relatively standardised hiring requirements across a range of levels from graduate to senior manager. The process efficiencies RPO providers deliver — consistent candidate experience, data-driven sourcing, technology integration, and scalable capacity — are most valuable when the challenge is process and volume rather than market access and quality.\n\nLarge consumer businesses, professional services firms with significant graduate intake programmes, and financial services organisations with substantial compliance and operations hiring are natural RPO clients. The economics of RPO — typically structured as a monthly management fee plus a per-hire fee that is lower than agency recruitment costs — work best when volume is sufficient to justify the infrastructure investment.\n\nRPO providers also add value through process standardisation and compliance: consistent application of employment law, structured diversity and inclusion frameworks, and data-driven insights into hiring performance. For organisations where governance and audit trail are important, RPO's process rigour is a genuine advantage."},{h:"Where RPO Falls Short for Senior Hires",b:"RPO is structurally unsuited to senior executive appointments for the same reasons that conventional recruitment agencies underperform at director level and above. The model is designed for process efficiency and volume throughput — exactly the wrong priorities for a CEO, CFO, or divisional MD search.\n\nRPO providers typically lack the market relationships, sector credibility, and seniority of consultant required to engage with passive candidates at C-suite level. A recruitment coordinator embedded in a client's HR team, using an ATS and LinkedIn Recruiter, cannot credibly approach a CTO who is running a major engineering organisation. The approach is wrong, the channel is wrong, and the message carries insufficient weight to generate serious interest.\n\nAdditionally, senior executive searches require a quality of assessment — competency-based interviews, structured referencing, detailed written reports — that RPO processes are not designed to deliver. RPO optimises for time-to-fill and cost-per-hire; executive search optimises for quality of hire. For roles where quality of hire is the dominant consideration, RPO is the wrong model regardless of cost."},{h:"The Right Architecture",b:"The most effective hiring organisations use a tiered model: RPO (or a well-resourced internal team) for volume hiring up to senior manager level, and retained executive search for director-level appointments and above. This architecture captures the cost efficiencies of scale for volume hiring while ensuring that the most important appointments receive the market access, assessment rigour, and senior consultant attention they require.\n\nSome organisations attempt to use their RPO provider for senior hires to simplify vendor management and capture economies of scale. This is rarely successful: the RPO provider's model is not designed for executive search, and extending it upward into the senior talent market typically delivers the process efficiency of RPO without the market coverage or assessment quality of executive search. The result is a senior hiring process that is internally tidy but externally ineffective.\n\nA pragmatic threshold: roles below \xa3100,000 base salary with an active candidate market are typically well-served by RPO or internal recruitment. Roles above \xa3100,000 where passive market access matters, or where the cost of a failed appointment is high, typically justify retained executive search."}],relatedLinks:[{label:"Headhunter vs Internal Talent Acquisition",href:"/comparisons/headhunter-vs-internal/"},{label:"When Should You Use a Headhunter?",href:"/guides/when-to-use-a-headhunter/"},{label:"How to Choose a Headhunter",href:"/guides/how-to-choose-a-headhunter/"},{label:"Do I Need a Headhunter? Take the Quiz",href:"/quiz/"}]},{slug:"headhunter-vs-internal",title:"Headhunter vs Internal Talent Acquisition",subtitle:"When to use internal talent acquisition versus retained executive search — and how the best organisations use both effectively.",sections:[{h:"The Case for Internal Talent Acquisition",b:"Internal talent acquisition teams have grown substantially in capability and sophistication over the past decade. The professionalisation of in-house recruiting — driven by better technology, data-driven approaches, and increasing investment in employer brand — means that internal teams at major organisations can deliver high-quality hiring outcomes across a wide range of roles, often more efficiently and cost-effectively than external agencies.\n\nThe advantages of internal talent acquisition are real and material. Internal recruiters know the organisation deeply — its culture, its politics, the unwritten expectations of what it takes to succeed, and the specific dynamics of the hiring managers they support. They are committed to the organisation's success rather than to placing a candidate and collecting a fee. They manage the candidate experience continuously, not just during active search. And over time, they build a network of potential candidates who know the organisation and are warm to future approaches.\n\nFor organisations with mature internal talent acquisition capability, extending that function to cover director-level roles is a natural ambition. The question is not whether internal teams are capable in principle, but whether the specific context of a senior appointment — passive market access, confidentiality requirements, assessment depth — is well-served by an internal approach."},{h:"Where Internal Teams Underperform at Senior Level",b:"Internal talent acquisition teams typically underperform at director level and above for three interconnected reasons: access, credibility, and capacity. Access: the most capable senior executives are passive candidates who are not visible to internal recruiters working from LinkedIn and their internal database. An internal recruiter approaching a FTSE 100 CFO's office is unlikely to receive a warm response, regardless of the quality of the opportunity.\n\nCredibility: senior candidates — particularly those considering a step change in their career — often prefer to engage with an independent, experienced search consultant who can provide honest, unmediated advice about the opportunity and the organisation. An internal recruiter, by definition, can only advocate for their employer. This limits the quality of the conversation and the honesty of the assessment they can offer to candidates who have real alternatives.\n\nCapacity: a genuine senior search — market mapping, longlist development, multi-stage assessment, offer management, onboarding support — is a significant resource commitment. Internal talent acquisition teams with a broad hiring portfolio rarely have the bandwidth to give a CEO or CFO search the depth of attention it requires without deprioritising other hiring. The result is a senior search that is under-resourced and slow."},{h:"Side-by-Side Comparison",b:"The following table compares internal talent acquisition and retained executive search across the dimensions most relevant to senior appointments.\n\n| Dimension | Internal Talent Acquisition | Retained Executive Search |\n|---|---|---|\n| Cost | Salary cost + tools | 25%–35% of candidate salary |\n| Organisational knowledge | High | Built through briefing |\n| Passive market access | Limited | High |\n| Candidate credibility | Limited for senior roles | High |\n| Assessment depth | Variable | Structured and consistent |\n| Confidentiality | Limited | High |\n| Capacity for senior searches | Constrained | Dedicated |\n| Market intelligence | Limited to own hiring | Broad sector knowledge |\n| Off-limits management | None | Contractual |\n| Guarantee | None | 6–12 months repeat search |"},{h:"Hybrid Models and Best Practice",b:"The most effective approach is not to choose between internal talent acquisition and executive search, but to define clearly where each adds most value. Internal teams are best positioned to manage volume hiring, employer brand, candidate experience, ATS management, and the sourcing and assessment of roles below director level. External search firms are best positioned to provide passive market access, independent candidate assessment, and senior consultant-led engagement for director-level appointments and above.\n\nIn practice, the most productive arrangement involves internal talent acquisition teams partnering actively with external search firms on senior mandates: managing the process, providing organisational context, and owning the candidate experience, while the search firm provides market mapping, direct candidate approach, and assessment rigour. This hybrid model captures the best of both capabilities.\n\nThe internal team's involvement in senior searches also builds organisational capability over time: through exposure to how a high-quality search firm structures an approach, conducts assessment, and manages offer negotiation, internal recruiters develop skills and frameworks they can apply in future searches. The relationship should be collaborative rather than adversarial."},{h:"When to Extend Internal Reach with a Search Partner",b:"Specific triggers that indicate an internal team should bring in an external search partner include: the role has been open for more than six weeks without a suitable shortlist emerging; the most credible candidates are all passive and have not responded to internal outreach; the appointment is sensitive or confidential and requires a controlled approach; the assessment requirements exceed the internal team's current capability; or the role is genuinely critical to organisational strategy and the cost of failure justifies the investment in external expertise.\n\nMany organisations also use external search partners for benchmarking purposes: commissioning a limited-scope search alongside an internal process to validate whether the internal shortlist represents the best available talent, or to provide an independent external view on compensation benchmarking. This hybrid approach is cost-effective and provides the quality assurance of an external perspective without the full cost of a retained search."}],relatedLinks:[{label:"Headhunter vs LinkedIn Recruiter",href:"/comparisons/headhunter-vs-linkedin/"},{label:"How Much Does a Headhunter Cost?",href:"/guides/headhunter-costs/"},{label:"Retained vs Contingent Search",href:"/comparisons/retained-vs-contingent/"},{label:"How to Choose a Headhunter",href:"/guides/how-to-choose-a-headhunter/"}]},{slug:"retained-vs-contingent",title:"Retained vs Contingent Search",subtitle:"The definitive comparison of retained and contingent executive search — fee structures, incentive dynamics, and what the difference means for your most important hire.",sections:[{h:"The Fundamental Distinction",b:'The difference between retained and contingent search is deceptively simple: when is the fee paid? In retained executive search, the client pays a portion of the fee before the search begins, securing the firm\'s exclusive, dedicated commitment to the assignment. In contingent recruitment, no fee is paid until a candidate is successfully placed — and if the search produces no hire, the recruiter receives nothing.\n\nThis single structural difference creates entirely different incentive landscapes and, consequently, entirely different search behaviours. Understanding how fee structure drives search methodology is essential for any organisation making a senior appointment, because the model you commission determines the quality of process and outcome you can expect.\n\nIt is important to note that the terms are sometimes blurred in market practice. Agencies occasionally describe hybrid arrangements — small upfront payments, milestone payments before placement — as "retained." The practical test of whether a search is genuinely retained remains: does the search firm receive a material, non-refundable payment before any candidate is presented? If not, the incentives are functionally contingent regardless of the label.'},{h:"How Incentives Shape Behaviour",b:"The retained model creates genuinely aligned incentives. Once the retainer is paid, the search firm is not under financial pressure to present candidates rapidly. It can take the time required to map the market properly, approach the most suitable candidates (who may require multiple conversations over several weeks before expressing genuine interest), and conduct thorough assessment before presenting a shortlist. Its commercial interest is in completing a high-quality search — because a poor outcome reflects on its reputation and jeopardises the instalment payments and future mandates.\n\nThe contingent model creates structurally misaligned incentives. The recruiter earns nothing until placement, which creates immediate pressure to present candidates quickly and advocate strongly for the individuals they have put forward. Working multiple mandates simultaneously is standard — the recruiter's portfolio model means no single search receives dedicated senior attention. The temptation to present good-enough candidates rather than best-available ones is embedded in the model's economics.\n\nThis is not a criticism of individual contingent recruiters, many of whom are professional and diligent. It is an observation about how financial structures drive organisational behaviour. The contingent model consistently produces faster first-candidate presentation and more aggressive advocacy — neither of which is necessarily what a senior appointment needs."},{h:"Detailed Comparison",b:"The following table compares retained and contingent search across every dimension relevant to senior hiring decisions.\n\n| Dimension | Retained Search | Contingent Recruitment |\n|---|---|---|\n| Fee timing | Staged: engagement, shortlist, offer | On successful placement only |\n| Typical fee | 25%–35% of salary | 15%–25% of salary |\n| Minimum fee | \xa330,000–\xa350,000 | \xa310,000–\xa320,000 |\n| Exclusivity | Always exclusive | Rarely exclusive |\n| Market coverage | Full market mapping (active + passive) | Active candidates + existing database |\n| Candidate assessment | Competency interviews, references, written reports | CV screening and basic interview |\n| Confidentiality | Controlled, discreet | Limited |\n| Consultant seniority | Senior partner led | Variable (often junior) |\n| Client resource required | Significant (briefing, feedback, interviews) | Light |\n| Off-limits management | Contractual, explicit | Typically absent |\n| Repeat search guarantee | Standard (6–12 months) | Rare |\n| Aftercare | 3–6 months standard | Typically none |\n| Best suited for | C-suite, board, director-level | Senior manager and below |"},{h:"Common Arguments for Contingent — and the Counterarguments",b:'**"Contingent is lower risk because we only pay for success."** This argument conflates fee risk with hiring risk. The fee is not the risk — the hire is. A contingent placement that fails costs three to five times the annual salary in aggregate: severance, lost momentum, team disruption, and the cost of re-running the search. The absence of a fee does not make a bad placement cost-free.\n\n**"We get more candidates from multiple agencies."** Briefing multiple contingent agencies on the same role at senior level almost always produces worse outcomes than a single committed retained firm. Candidates are approached multiple times by different agencies (damaging the credibility of the opportunity), the confidentiality of the search is compromised, and the agencies race to present CVs without adequate assessment. Volume of candidates is not the same as quality of shortlist.\n\n**"Retained search takes too long."** A well-run retained search with a committed client takes 10–14 weeks, which is typically faster than a failed contingent search that cycles through multiple agencies without producing a suitable shortlist. The perception that contingent is faster is partly a function of speed to first-CV — which is not the same as speed to successful hire.\n\n**"We can run both in parallel."** Most retained search firms require exclusivity as a condition of the engagement, which makes running contingent agencies simultaneously a breach of the terms. More fundamentally, parallel approaches undermine the quality of the retained search by contaminating the candidate market and compromising the controlled approach strategy that makes executive search effective.'},{h:"Making the Right Choice",b:"The decision between retained and contingent search should be driven by the nature of the role, not the desire to minimise upfront fee commitment. For roles below \xa380,000–\xa3100,000 where the active candidate market is sufficient and the cost of failure is manageable, contingent recruitment is a reasonable and often appropriate choice. For senior appointments above \xa3100,000 where passive market access matters, confidentiality is required, or the strategic importance of the role justifies rigorous assessment, retained search is the appropriate model.\n\nA practical test: if you can imagine commissioning three contingent agencies on this role and getting an acceptable shortlist within four weeks, the contingent model may serve you adequately. If the best candidate for this role is almost certainly not looking, will not respond to InMail from an unknown recruiter, and needs a personal approach from a trusted intermediary — you need retained executive search.\n\nThe total cost comparison also bears honest examination. A contingent placement at 20% that fails, requires a re-search, and costs three times salary in aggregate may ultimately cost more than a retained search at 30% that places the right person in twelve weeks and comes with a twelve-month guarantee."}],relatedLinks:[{label:"How Much Does a Headhunter Cost?",href:"/guides/headhunter-costs/"},{label:"Use Our Fee Estimator",href:"/estimator/"},{label:"Headhunter vs LinkedIn Recruiter",href:"/comparisons/headhunter-vs-linkedin/"},{label:"The Real Cost of a Bad Senior Hire",href:"/blog/cost-of-bad-hire/"}]}];let h={"@context":"https://schema.org","@graph":[{"@type":"Organization","@id":"https://headhunters.co.uk/#org",name:"headhunters.co.uk",url:"https://headhunters.co.uk",description:"The UK's leading authority on executive search and headhunting — guides, tools, and resources for businesses making senior hires.",sameAs:["https://elliotmarsh.com","https://executiveheadhunters.co.uk"]},{"@type":"WebPage","@id":"https://headhunters.co.uk/comparisons/",name:"Executive Search Comparisons",url:"https://headhunters.co.uk/comparisons/",publisher:{"@id":"https://headhunters.co.uk/#org"}}]};var d=!0;function u(){return(0,i.jsxs)(s.Z,{title:"Executive Search Comparisons",description:"Clear, honest comparisons of executive search, LinkedIn Recruiter, RPO, internal talent acquisition, and contingent recruitment — to help you make the right hiring decision.",canonical:"https://headhunters.co.uk/comparisons/",schema:h,children:[(0,i.jsx)("div",{style:{background:"linear-gradient(135deg, ".concat(c.Z.dark," 0%, ").concat(c.Z.navy," 100%)"),padding:"56px 24px 48px",textAlign:"center"},children:(0,i.jsxs)("div",{style:{maxWidth:680,margin:"0 auto"},children:[(0,i.jsx)("p",{style:{fontSize:12,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:c.Z.gold,marginBottom:14},children:"Comparisons"}),(0,i.jsx)("h1",{style:{fontSize:"clamp(26px, 4vw, 42px)",fontWeight:800,color:"#fff",marginBottom:16,lineHeight:1.15},children:"Executive Search vs The Alternatives"}),(0,i.jsx)("p",{style:{fontSize:16,color:"rgba(255,255,255,0.72)",lineHeight:1.6},children:"Honest comparisons to help you choose the right hiring approach for your most important appointments."})]})}),(0,i.jsx)("section",{style:{padding:"56px 24px",maxWidth:900,margin:"0 auto"},children:(0,i.jsx)("div",{style:{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(300px, 1fr))",gap:20},children:l.map(e=>(0,i.jsx)(r(),{href:"/comparisons/".concat(e.slug,"/"),style:{textDecoration:"none"},children:(0,i.jsxs)(o.Z,{style:{height:"100%",display:"flex",flexDirection:"column"},children:[(0,i.jsx)("span",{style:{display:"inline-block",background:"".concat(c.Z.accent,"15"),color:c.Z.accent,fontSize:11,fontWeight:700,letterSpacing:"0.06em",textTransform:"uppercase",padding:"3px 8px",borderRadius:4,marginBottom:10},children:"Comparison"}),(0,i.jsx)("h2",{style:{fontSize:16,fontWeight:700,color:c.Z.dark,marginBottom:8,lineHeight:1.3},children:e.title}),(0,i.jsx)("p",{style:{fontSize:13.5,color:c.Z.tl,lineHeight:1.6,flexGrow:1,marginBottom:16},children:e.subtitle}),(0,i.jsx)("span",{style:{fontSize:13,color:c.Z.accent,fontWeight:600},children:"Read comparison →"})]})},e.slug))})})]})}}},function(e){e.O(0,[996,326,888,774,179],function(){return e(e.s=7828)}),_N_E=e.O()}]);